# Create project directory
mkdir my-node-app && cd my-node-app

# Create package.json
cat > package.json << EOF
{
  "name": "docker-app",
  "version": "1.0.0",
  "main": "server.js",
  "scripts": {
    "start": "node server.js"
  },
  "dependencies": {
    "express": "^4.18.0"
  }
}
EOF

# Create server.js
cat > server.js << EOF
const express = require('express');
const app = express();

app.get('/', (req, res) => {
  res.send('<h1>Hello from Docker! 🐳</h1>');
});

app.listen(3000, () => {
  console.log('App running on port 3000');
});
EOF
